    body: "<p>\u00a0 \u00a0 Welding boom column\u00a0 \u00a0main For all arc welding processes, it is important that the welding head be rigidly mounted over the part to be welded to obtain the highest quality weld results. Any vibration or instability of the weld head mounting will have an effect upon the arc length and produce inferior results. Welding manipulator is used when the weld head has to be moved to a position relative to the work piece. Welding manipulator provide the perfect solution as the boom can be lifted and lowered on the column and can be extended or retracted as required, The ends of\u00a0 boom are machined to carry a welding head.</p>\n<p><img alt=\"welding boom column\" height=\"900\" src=\"/images/wm/wm-00.jpg\" title=\"welding boom column\" width=\"1200\"/></p>",
    images: [{"url": "/images/wm/wm-00.jpg", "alt": "wm 00"}, {"url": "/images/wm/52B22521-1452-4962-BE8B-5569E5D27EB420161123-150.jpg", "alt": "52B22521 1452 4962 BE8B 5569E5D27EB420161123 150"}, {"url": "/images/WMomni/20100302001-0.jpg", "alt": "20100302001 0"}, {"url": "/images/WMomni/20100302002.jpg", "alt": "20100302002"}, {"url": "/images/WMomni/20100306017.jpg", "alt": "20100306017"}, {"url": "/images/WMomni/20110309897.jpg", "alt": "20110309897"}, {"url": "/images/WMomni/20110406949.jpg", "alt": "20110406949"}, {"url": "/images/WMomni/2016-07-21 141752.jpg", "alt": "2016 07 21 141752"}, {"url": "/images/WMomni/2016-07-21 141952.jpg", "alt": "2016 07 21 141952"}, {"url": "/images/WMomni/2016-07-21 142018.jpg", "alt": "2016 07 21 142018"}, {"url": "/images/WMomni/2016-07-21 142031.jpg", "alt": "2016 07 21 142031"}, {"url": "/images/WMomni/2016-07-21 142152.jpg", "alt": "2016 07 21 142152"}, {"url": "/images/WMomni/2016-07-21 142228.jpg", "alt": "2016 07 21 142228"}, {"url": "/images/WMomni/63.jpg", "alt": "63"}],
