    description: "1) Overview of beveling machine",
    body: "<p>1) Overview of beveling machine</p>\n<p><strong>GD20 rolling cutting beveling machine for plate weld</strong></p>",
    images: [{"url": "/images/xbj/GD20-2.jpg", "alt": "GD20 2"}, {"url": "/images/xbj/table-1.jpg", "alt": "table 1"}, {"url": "/images/xbj/dx-00.jpg", "alt": "dx 00"}, {"url": "/images/xbj/dx-01.jpg", "alt": "dx 01"}, {"url": "/images/xbj/dx-02.jpg", "alt": "dx 02"}, {"url": "/images/xbj/dx-03.jpg", "alt": "dx 03"}, {"url": "/images/xbj/dx-04.jpg", "alt": "dx 04"}, {"url": "/images/xbj/dx-05.jpg", "alt": "dx 05"}, {"url": "/images/xbj/dx-06.jpg", "alt": "dx 06"}, {"url": "/images/xbj/GD20.jpg", "alt": "GD20"}, {"url": "/images/xbj/IMG_0291.jpg", "alt": "IMG 0291"}, {"url": "/images/xbj/IMG_1573.jpg", "alt": "IMG 1573"}, {"url": "/images/xbj/IMG_2041.jpg", "alt": "IMG 2041"}],
